use std::fs::File;

// The '?' operator returns the error immediately to the caller if File::open fails
fn read_config() -> Result<File, std::io::Error> {
    let file = File::open("config.toml")?;
    Ok(file)
}

trait Speak { fn speak(&self); }

struct Dog;
impl Speak for Dog { fn speak(&self) { println!("Woof"); } }

// Generic function with a Trait Bound
fn make_sound<T: Speak>(animal: &T) {
    animal.speak();
}

fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

use std::rc::Rc;
use std::cell::RefCell;
fn main() {
    let shared_state = Rc::new(RefCell::new(5));
    *shared_state.borrow_mut() += 1; // Interior mutability
}

use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let counter = Arc::new(Mutex::new(0));
    let mut handles = vec![];

    for _ in 0..10 {
        let counter = Arc::clone(&counter);
        handles.push(thread::spawn(move || {
            let mut num = counter.lock().unwrap();
            *num += 1;
        }));
    }
}

